+    fn actionable_excludes_children_of_blocked_parent_epic() {
+        // Parent epic E is blocked by blocker B.
+        // Child task C has a parent-child dep on E.
+        // C should NOT be actionable because its parent E is blocked.
+        let issues = vec![
+            Issue {
+                id: "B".to_string(),
