+                status: "blocked".to_string(),
+                issue_type: "epic".to_string(),
+                priority: 2,
+                dependencies: vec![Dependency {
+                    issue_id: "E".to_string(),
+                    depends_on_id: "B".to_string(),
+                    dep_type: "blocks".to_string(),
+                    ..Dependency::default()
+                }],
+                ..Issue::default()
+            },
